            <script>
                (function () {
                    // ===== FAQ Accordion (5 sesuai schema) =====
                    const faqButtons = document.querySelectorAll(".BANDAR-container .acc-item");
                    faqButtons.forEach((btn, idx) => {
                        const panel = btn.nextElementSibling;

                        const qId = `RATU898-faq-q-${idx}`;
                        const pId = `RATU898-faq-p-${idx}`;
                        btn.id = qId;
                        panel.id = pId;
                        btn.setAttribute("aria-controls", pId);
                        panel.setAttribute("aria-labelledby", qId);

                        btn.addEventListener("click", () => {
                            const isOpen = btn.getAttribute("aria-expanded") === "true";
                            faqButtons.forEach(b => {
                                b.setAttribute("aria-expanded", "false");
                                b.nextElementSibling.classList.remove("is-open");
                            });
                            if (!isOpen) {
                                btn.setAttribute("aria-expanded", "true");
                                panel.classList.add("is-open");
                            }
                        });
                    });

                    // ===== PENILAIAN-TT80 Auto Slide (6 sesuai schema) =====
                    const slider = document.getElementById("TT80Slider");
                    const track = slider?.querySelector(".penilaian-mwt-track");
                    const cards = track ? Array.from(track.children) : [];
                    const dotsWrap = slider?.querySelector(".penilaian-mwt-dots");

                    if (!slider || !track || cards.length === 0) return;

                    let index = 0;
                    let perView = 1;
                    let timer = null;

                    function calcPerView() {
                        const w = window.innerWidth;
                        if (w >= 980) return 3;
                        if (w >= 720) return 2;
                        return 1;
                    }

                    function buildDots() {
                        if (!dotsWrap) return;
                        dotsWrap.innerHTML = "";
                        const pages = Math.ceil(cards.length / perView);
                        for (let i = 0; i < pages; i++) {
                            const d = document.createElement("span");
                            d.className = "penilaian-mwt-dot" + (i === 0 ? " is-active" : "");
                            dotsWrap.appendChild(d);
                        }
                    }

                    function setActiveDot(page) {
                        if (!dotsWrap) return;
                        Array.from(dotsWrap.children).forEach((d, i) => {
                            d.classList.toggle("is-active", i === page);
                        });
                    }

                    function slideTo(page) {
                        const cardWidth = cards[0].getBoundingClientRect().width;
                        const gap = parseFloat(getComputedStyle(track).gap) || 0;
                        const step = (cardWidth + gap) * perView;

                        const maxPage = Math.max(0, Math.ceil(cards.length / perView) - 1);
                        index = page > maxPage ? 0 : page;

                        track.style.transform = `translateX(-${step * index}px)`;
                        setActiveDot(index);
                    }

                    function start() {
                        stop();
                        timer = setInterval(() => slideTo(index + 1), 3200);
                    }
                    function stop() {
                        if (timer) clearInterval(timer);
                        timer = null;
                    }

                    function refresh() {
                        perView = calcPerView();
                        buildDots();
                        slideTo(0);
                        start();
                    }

                    slider.addEventListener("mouseenter", stop);
                    slider.addEventListener("mouseleave", start);
                    slider.addEventListener("touchstart", stop, { passive: true });
                    slider.addEventListener("touchend", start, { passive: true });

                    window.addEventListener("resize", () => {
                        clearTimeout(window.__TT80ResizeT);
                        window.__TT80ResizeT = setTimeout(refresh, 140);
                    });

                    refresh();
                })();
            </script>
            
